  line-height:1.1;
  font-weight:700;
  color: #fff; /* fallback */
}

/* Rainbow text effect - uses gradient clipped to text */
.rainbow{
  background: linear-gradient(90deg, #ff004f, #ff7a00, #ffdd00, #00c853, #00b0ff, #7c4dff);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: rainbowShift 4s linear infinite;
  background-size: 300% 100%;
}

@keyframes rainbowShift{
  0%{background-position:0% 50%}
  50%{background-position:100% 50%}
  100%{background-position:0% 50%}
}

button{padding:0.4rem 0.8rem;border-radius:6px;border:none;background:#1f2937;color:#fff;cursor:pointer}
.note{opacity:0.8;font-size:0.9rem}


--- src/server.ts ---
import express from 'express';
import path from 'path';

const app = express();
const PORT = process.env.PORT || 3000;

// Serve the public directory (static files)
const publicDir = path.join(__dirname, '..', 'public');
app.use(express.static(publicDir));

// Ensure root serves index.html explicitly
app.get('/', (req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

if (require.main === module) {
  app.listen(PORT, () => {
    // eslint-disable-next-line no-console
    console.log(`Server listening on http://localhost:${PORT}`);
  });
}

export default app;


--- tests/server.test.ts ---
import request from 'supertest';
import app from '../src/server';

describe('GET /', () => {
  it('responds with HTML containing the exact Hello World heading and id/class', async () => {
    const res = await request(app).get('/').expect(200).expect('Content-Type', /html/);
    const body: string = res.text;

    // Must contain exact text
    expect(body).toEqual(expect.stringContaining('Hello World'));

    // Heading element with id="hello"
    expect(body).toMatch(/<h1[^>]*id=["']hello["'][^>]*>\s*Hello World\s*<\/h1>/);

    // Ensure script and stylesheet are referenced so JS/CSS can target the element
    expect(body).toEqual(expect.stringContaining('styles.css'));
    expect(body).toEqual(expect.stringContaining('app.js'));
  });
});


